import { useContext, useEffect } from 'react';
import './App.css';
import BlogPage from './pages/BlogPage/BlogPage';
import HomePage from './pages/HomePage/HomePage';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import AuthContext from './components/AuthContext/AuthContext';
import Header from './components/Header/Header';
import Footer from './components/Footer/Footer';
import CoursesPage from './pages/CoursesPage/CoursesPage';
import AboutPage from './pages/AboutPage/AboutPage';
import SingleCoursePage from './pages/SingleCoursePage/SingleCoursePage';
import LoginPage from './pages/LoginPage/LoginPage';



function App() {

  const {isAuthenticated} = useContext(AuthContext);

  useEffect(() => {
    const scrollContainer = document.querySelector('.scroll-container');

    function preventAddressBar() {
      scrollContainer.scrollTop = 1;
      setTimeout(() => {
        scrollContainer.scrollTop = 0;
      }, 0);
    }

    // Inicijalno postavi poziciju skrola na 1px
    preventAddressBar();

    // Resetuj poziciju skrola na 1px kada korisnik skroluje do vrha
    scrollContainer.addEventListener('scroll', () => {
      if (scrollContainer.scrollTop === 0) {
        preventAddressBar();
      }
    });

    // Cleanup event listener on component unmount
    return () => {
      scrollContainer.removeEventListener('scroll', () => {
        if (scrollContainer.scrollTop === 0) {
          preventAddressBar();
        }
      });
    };
  }, []);


  return (
    <div className="App">
      <Router>
        <Header />
        <div className="scroll-container"> 
          <Routes>
            <Route path={"/"} element={<HomePage />} /> 
            {isAuthenticated ?  <Route path={"/blog"} element={<BlogPage />} > </Route> : <Route path={"/login"} element={<LoginPage />} />}  
            <Route path={"/kursevi"} element={<CoursesPage />} />
            <Route path={"/informacije"} element={<AboutPage />} /> 
            <Route path={"/kurs/:id"} element={<SingleCoursePage />} />
            <Route path={"/login"} element={<LoginPage />} />
          </Routes>

        <Footer /> 
        </div>
      </Router>

    </div>
  );
}

export default App;
